package Logical;

public class LogicalOp {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		boolean x = true;
		boolean y = false;
		System.out.println("xandy "+(x&&y));
		System.out.println("xandy "+(x||y));
		System.out.println("!x "+(!x)); 
		System.out.println("x!=y  "+(x!=y));
	}

}
